#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y, P, Q;
        scanf("%d %d %d %d", &X, &Y, &P, &Q);
        int chef = X + P * 10;
        int chefina = Y + Q * 10;
        if (chef < chefina) {
            printf("Chef\n");
        } else if (chef > chefina) {
            printf("Chefina\n");
        } else {
            printf("Draw\n");
        }
    }
    return 0;
}

