            st = new StringTokenizer(br.readLine());
            int X = Integer.parseInt(st.nextToken());
            int Y = Integer.parseInt(st.nextToken());
            int P = Integer.parseInt(st.nextToken());
            int Q = Integer.parseInt(st.nextToken());
            int chef = X + P * 10;
            int chefina = Y + Q * 10;
            if (chef < chefina) sb.append("Chef\n");
            else if (chef > chefina) sb.append("Chefina\n");
            else sb.append("Draw\n");
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        X = int(next(it)); Y = int(next(it)); P = int(next(it)); Q = int(next(it))
        chef = X + P * 10
        chefina = Y + Q * 10
        if chef < chefina:
            out_lines.append("Chef")
        elif chef > chefina:
            out_lines.append("Chefina")
        else:
            out_lines.append("Draw")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

